{"metadata":{"kernelspec":{"language":"python","display_name":"Python 3","name":"python3"},"language_info":{"name":"python","version":"3.12.12","mimetype":"text/x-python","codemirror_mode":{"name":"ipython","version":3},"pygments_lexer":"ipython3","nbconvert_exporter":"python","file_extension":".py"}},"nbformat_minor":4,"nbformat":4,"cells":[{"cell_type":"code","source":"import torch\nfrom transformers import AutoModelForCausalLM, AutoTokenizer\nfrom peft import LoraConfig, get_peft_model\n\nfrom kaggle_secrets import UserSecretsClient\nfrom huggingface_hub import login\n\n# 從 Kaggle Secrets 抓取 Token\nuser_secrets = UserSecretsClient()\nhf_token = user_secrets.get_secret(\"HF_TOKEN\")\n\n# 登入 Hugging Face\nlogin(token=hf_token)\n\n# 之後再跑你原本的 AutoModelForCausalLM.from_pretrained(...)\n\"\"\"\n我會想知道 這邊每一段的細節是甚麼，背後的運作模式，以及他確切來說到底會從HF下載下來什麼檔案，\n為什麼 llama 願意開源? 那它的商業機密怎麼半? 他會開源什麼 但不公開甚麼?\n為什麼我能下載他的model 然後甚至能用LoRA去 finetune? \n> lora_config = LoraConfig() \n這個 config 裡面在幹嘛?\n> # 5. 將 LoRA 外掛應用到模型上\n> model = get_peft_model(model, lora_config)\n具體來說，數學上，這是怎麼做到的？ 怎麼將 LoRA 外掛應用到模型上? 怎麼插入的?\nlora 具體來說它的運作機制是甚麼？(這就要看老師的講義了)\n\"\"\"\n\ndef setup_model_and_lora():\n    \"\"\"\n    載入 Llama-3.2-1B-Instruct 模型，並套用 LoRA 微調設定。\n    \"\"\"\n    # 1. 指定作業規定的模型名稱\n    model_name = \"meta-llama/Llama-3.2-1B-Instruct\"\n    \n    print(f\"Loading tokenizer and model: {model_name}...\")\n    \n    # 2. 載入 Tokenizer (分詞器：負責把人類文字切成模型看得懂的數字)\n    # Llama 3 預設沒有 padding token，我們通常會把 eos_token 設為 padding token\n    tokenizer = AutoTokenizer.from_pretrained(model_name)\n    tokenizer.pad_token = tokenizer.eos_token\n    tokenizer.padding_side = \"right\" # 訓練時通常靠右對齊\n    \n    # 3. 載入基礎模型 (Base Model)\n    # 為了節省 VRAM (顯示卡記憶體)，我們通常會用 bfloat16 或 float16 載入\n    model = AutoModelForCausalLM.from_pretrained(\n        model_name,\n        device_map=\"auto\", # 自動將模型分配到 GPU 上\n        torch_dtype=torch.bfloat16, # 使用 bfloat16 可以節省記憶體並加速\n    )\n    \n    # 4. 設定 LoRA 參數 (LoraConfig)\n    print(\"Setting up LoRA configuration...\")\n    lora_config = LoraConfig(\n        r=16,               # r (Rank): 便利貼的大小。數值越大能學到越多細節，但越耗資源 (通常設 8, 16, 32)\n        lora_alpha=32,      # lora_alpha: 縮放係數，通常設定為 r 的 2 倍\n        target_modules=[    # 指定要貼便利貼的注意力機制模組 (Llama 通常是 q_proj, v_proj 等)\n            \"q_proj\", \n            \"k_proj\", \n            \"v_proj\", \n            \"o_proj\"\n        ],\n        lora_dropout=0.05,  # Dropout 比例，用來防止過度擬合 (Overfitting)\n        bias=\"none\",        # 通常不需要訓練 bias\n        task_type=\"CAUSAL_LM\" # 我們的任務是語言模型生成 (Causal Language Modeling)\n    )\n    \n    # 5. 將 LoRA 外掛應用到模型上\n    model = get_peft_model(model, lora_config)\n    \n    # 印出可以訓練的參數比例，你會發現我們只需要訓練不到 1% 的參數！\n    model.print_trainable_parameters()\n    \n    return model, tokenizer\n\n# ==========================================\n# 實際執行範例\n# ==========================================\nif __name__ == \"__main__\":\n    # 呼叫函式來測試是否能成功載入\n    # 注意：這一步會需要下載約 2GB~3GB 的模型權重，請確保網路暢通\n    model, tokenizer = setup_model_and_lora()\n    print(\"模型與 LoRA 設定完成！準備進入訓練階段。\")","metadata":{"_uuid":"68b25969-d887-4048-bac9-96a566b8766f","_cell_guid":"a80baa08-2122-431a-996d-5c6496280ad5","trusted":true,"collapsed":false,"jupyter":{"outputs_hidden":false},"execution":{"iopub.status.busy":"2026-03-17T18:40:15.168935Z","iopub.execute_input":"2026-03-17T18:40:15.169282Z","iopub.status.idle":"2026-03-17T18:40:27.950468Z","shell.execute_reply.started":"2026-03-17T18:40:15.169251Z","shell.execute_reply":"2026-03-17T18:40:27.949066Z"}},"outputs":[{"name":"stdout","text":"Loading tokenizer and model: meta-llama/Llama-3.2-1B-Instruct...\n","output_type":"stream"},{"output_type":"display_data","data":{"text/plain":"config.json:   0%|          | 0.00/877 [00:00<?, ?B/s]","application/vnd.jupyter.widget-view+json":{"version_major":2,"version_minor":0,"model_id":"a0940605522b4e28a68ab63ade95f8e5"}},"metadata":{}},{"output_type":"display_data","data":{"text/plain":"tokenizer_config.json: 0.00B [00:00, ?B/s]","application/vnd.jupyter.widget-view+json":{"version_major":2,"version_minor":0,"model_id":"1d36819c31e64545b1a5906518adff38"}},"metadata":{}},{"output_type":"display_data","data":{"text/plain":"tokenizer.json: 0.00B [00:00, ?B/s]","application/vnd.jupyter.widget-view+json":{"version_major":2,"version_minor":0,"model_id":"39a580097b4f40c8afc1c58051c52e98"}},"metadata":{}},{"output_type":"display_data","data":{"text/plain":"special_tokens_map.json:   0%|          | 0.00/296 [00:00<?, ?B/s]","application/vnd.jupyter.widget-view+json":{"version_major":2,"version_minor":0,"model_id":"7a8d7ffa5c5a4a79a05c72a9f8c2ce09"}},"metadata":{}},{"name":"stderr","text":"`torch_dtype` is deprecated! Use `dtype` instead!\n","output_type":"stream"},{"output_type":"display_data","data":{"text/plain":"model.safetensors:   0%|          | 0.00/2.47G [00:00<?, ?B/s]","application/vnd.jupyter.widget-view+json":{"version_major":2,"version_minor":0,"model_id":"5d4d6403fc2d4e118f47dfb3a31ed0f0"}},"metadata":{}},{"output_type":"display_data","data":{"text/plain":"Loading weights:   0%|          | 0/146 [00:00<?, ?it/s]","application/vnd.jupyter.widget-view+json":{"version_major":2,"version_minor":0,"model_id":"794ab614a1834c34b9ebd5c1c0a55372"}},"metadata":{}},{"output_type":"display_data","data":{"text/plain":"generation_config.json:   0%|          | 0.00/189 [00:00<?, ?B/s]","application/vnd.jupyter.widget-view+json":{"version_major":2,"version_minor":0,"model_id":"1aeb92ee23fa400ba1ce3559c1c2bba8"}},"metadata":{}},{"name":"stdout","text":"Setting up LoRA configuration...\n","output_type":"stream"},{"name":"stderr","text":"WARNING:torchao.kernel.intmm:Warning: Detected no triton, on systems without Triton certain kernels will not work\n","output_type":"stream"},{"name":"stdout","text":"trainable params: 3,407,872 || all params: 1,239,222,272 || trainable%: 0.2750\n模型與 LoRA 設定完成！準備進入訓練階段。\n","output_type":"stream"}],"execution_count":2}]}